typedef guint GumX86MetaReg;
typedef struct _GumX86RegInfo GumX86RegInfo;
typedef guint GumX86LabelRefSize;
typedef struct _GumX86LabelRef GumX86LabelRef;

enum _GumX86MetaReg
{
  GUM_X86_META_XAX = 0,
  GUM_X86_META_XCX,
  GUM_X86_META_XDX,
  GUM_X86_META_XBX,
  GUM_X86_META_XSP,
  GUM_X86_META_XBP,
  GUM_X86_META_XSI,
  GUM_X86_META_XDI,
  GUM_X86_META_R8,
  GUM_X86_META_R9,
  GUM_X86_META_R10,
  GUM_X86_META_R11,
  GUM_X86_META_R12,
  GUM_X86_META_R13,
  GUM_X86_META_R14,
  GUM_X86_META_R15
};

struct _GumX86RegInfo
{
  GumX86MetaReg meta;
  guint width;
  guint index;
  gboolean index_is_extended;
};

enum _GumX86LabelRefSize
{
  GUM_LREF_SHORT,
  GUM_LREF_NEAR,
  GUM_LREF_ABS
};

struct _GumX86LabelRef
{
  gconstpointer id;
  guint8 * address;
  GumX86LabelRefSize size;
};

