/* ---- module (main-module range for tests) ------------------------------- */

struct _GumModule
{
  gchar name[MAX_PATH];
  gchar path[MAX_PATH];
  GumMemoryRange range;
  gboolean initialized;
};

static GumModule gum_main_module;

static GumModule *
gum_main_module_get (void)
{
  GumModule * m = &gum_main_module;
  HMODULE handle;
  MODULEINFO info;
  DWORD len;

  if (m->initialized)
    return m;

  handle = GetModuleHandleW (NULL);

  len = GetModuleFileNameA (handle, m->path, sizeof (m->path));
  if (len != 0)
  {
    const char * slash = m->path;
    const char * p;
    for (p = m->path; *p != '\0'; p++)
    {
      if (*p == '\\' || *p == '/')
        slash = p + 1;
    }
    strncpy (m->name, slash, sizeof (m->name) - 1);
  }

  if (GetModuleInformation (GetCurrentProcess (), handle, &info,
      sizeof (info)))
  {
    m->range.base_address = GUM_ADDRESS (info.lpBaseOfDll);
    m->range.size = info.SizeOfImage;
  }

  m->initialized = TRUE;
  return m;
}

GumModule *
gum_process_get_main_module (void)
{
  return gum_main_module_get ();
}

const gchar *
gum_module_get_name (GumModule * self)
{
  return self->name;
}

const gchar *
gum_module_get_path (GumModule * self)
{
  return self->path;
}

const GumMemoryRange *
gum_module_get_range (GumModule * self)
{
  return &self->range;
}

GumAddress
gum_module_find_export_by_name (GumModule * self,
                                const gchar * symbol_name)
{
  (void) self;
  return GUM_ADDRESS (GetProcAddress (GetModuleHandleW (NULL), symbol_name));
}

/* ==== source: gum_msvc_intrinsics.c ==== */
/*
 * hoox — definitions for MSVC segment intrinsics that clang (in GNU mode)
 * references from the Windows TLS backend but does not provide as builtins.
 *
 * Licence: wxWindows Library Licence, Version 3.1
 */

/* clang.exe defines both __clang__ and _MSC_VER; it references __writegsqword
 * from the TLS backend but does not always provide it as a builtin, so define
 * it here for the clang/gcc toolchains. */
#if defined (_WIN32) && (defined (__clang__) || defined (__GNUC__))

#include <stdint.h>

# if defined (__x86_64__) || defined (_M_X64)

/* GS-relative 64-bit store: [gs_base + offset] = data. */
void
__writegsqword (unsigned long offset,
                unsigned long long data)
{
  __asm__ __volatile__ ("movq %1, %%gs:(%0)"
      :
      : "r" ((uint64_t) offset), "r" ((uint64_t) data)
      : "memory");
}

# else

/* FS-relative 32-bit store: [fs_base + offset] = data. */
void
__writefsdword (unsigned long offset,
                unsigned long data)
{
  __asm__ __volatile__ ("movl %1, %%fs:(%0)"
      :
      : "r" ((uint32_t) offset), "r" ((uint32_t) data)
      : "memory");
}

# endif

#endif

/* ==== source: gumcpucontext-x86.c ==== */
/*
 * Copyright (C) 2008-2017 Ole André Vadla Ravnås <oleavr@nowsecure.com>
 *
 * Licence: wxWindows Library Licence, Version 3.1
 */


gpointer
gum_cpu_context_get_nth_argument (GumCpuContext * self,
                                  guint n)
{
  gpointer * stack_argument;

#if GLIB_SIZEOF_VOID_P == 4
  stack_argument = (gpointer *) (self->esp + 4);
  return stack_argument[n];
#else
  stack_argument = (gpointer *) (self->rsp + 8);
  switch (n)
  {
# if GUM_NATIVE_ABI_IS_UNIX
    case 0:  return (gpointer) self->rdi;
    case 1:  return (gpointer) self->rsi;
    case 2:  return (gpointer) self->rdx;
    case 3:  return (gpointer) self->rcx;
    case 4:  return (gpointer) self->r8;
    case 5:  return (gpointer) self->r9;
    default: return            stack_argument[n - 6];
# else
    case 0:  return (gpointer) self->rcx;
    case 1:  return (gpointer) self->rdx;
    case 2:  return (gpointer) self->r8;
    case 3:  return (gpointer) self->r9;
    default: return            stack_argument[n];
# endif
  }
#endif
}

void
gum_cpu_context_replace_nth_argument (GumCpuContext * self,
                                      guint n,
                                      gpointer value)
{
  gpointer * stack_argument;

#if GLIB_SIZEOF_VOID_P == 4
  stack_argument = (gpointer *) (self->esp + 4);
  stack_argument[n] = value;
#else
  stack_argument = (gpointer *) (self->rsp + 8);
  switch (n)
  {
# if GUM_NATIVE_ABI_IS_UNIX
    case 0:  self->rdi             = (guint64) value; break;
    case 1:  self->rsi             = (guint64) value; break;
    case 2:  self->rdx             = (guint64) value; break;
    case 3:  self->rcx             = (guint64) value; break;
    case 4:  self->r8              = (guint64) value; break;
    case 5:  self->r9              = (guint64) value; break;
    default: stack_argument[n - 6] =           value; break;
# else
    case 0:  self->rcx             = (guint64) value; break;
    case 1:  self->rdx             = (guint64) value; break;
    case 2:  self->r8              = (guint64) value; break;
    case 3:  self->r9              = (guint64) value; break;
    default: stack_argument[n]     =           value; break;
# endif
  }
#endif
}

gpointer
gum_cpu_context_get_return_value (GumCpuContext * self)
{
#if GLIB_SIZEOF_VOID_P == 4
  return (gpointer) self->eax;
#else
  return (gpointer) self->rax;
#endif
}

void
gum_cpu_context_replace_return_value (GumCpuContext * self,
                                      gpointer value)
{
#if GLIB_SIZEOF_VOID_P == 4
  self->eax = (guint32) value;
#else
  self->rax = (guint64) value;
#endif
}

/* ==== source: gumcpu-x86.c ==== */
/*
 * hoox — x86 CPU feature query (extracted from frida-gum gum.c).
 *
 * Licence: wxWindows Library Licence, Version 3.1
 * Copyright (C) Ole André Vadla Ravnås and contributors.
 */


#ifdef _MSC_VER
# include <intrin.h>
#else
# include <cpuid.h>
#endif

static GumCpuFeatures gum_do_query_cpu_features (void);
static gboolean gum_get_cpuid (guint level, guint * a, guint * b, guint * c,
    guint * d);

GumCpuFeatures
gum_query_cpu_features (void)
{
  static gsize cached_result = 0;

  if (g_once_init_enter (&cached_result))
  {
    GumCpuFeatures features = gum_do_query_cpu_features ();

    g_once_init_leave (&cached_result, features + 1);
  }

  return cached_result - 1;
}

static GumCpuFeatures
gum_do_query_cpu_features (void)
{
  GumCpuFeatures features = 0;
  gboolean cpu_supports_avx2 = FALSE;
  gboolean cpu_supports_cet_ss = FALSE;
  gboolean os_enabled_xsave = FALSE;
  guint a, b, c, d;

  if (gum_get_cpuid (7, &a, &b, &c, &d))
  {
    cpu_supports_avx2 = (b & (1 << 5)) != 0;
    cpu_supports_cet_ss = (c & (1 << 7)) != 0;
  }

  if (gum_get_cpuid (1, &a, &b, &c, &d))
    os_enabled_xsave = (c & (1 << 27)) != 0;

  if (cpu_supports_avx2 && os_enabled_xsave)
    features |= GUM_CPU_AVX2;

  if (cpu_supports_cet_ss)
    features |= GUM_CPU_CET_SS;

  return features;
}

static gboolean
gum_get_cpuid (guint level,
               guint * a,
               guint * b,
               guint * c,
               guint * d)
{
#ifdef _MSC_VER
  gint info[4];
  guint n;

  __cpuid (info, 0);
  n = info[0];
  if (n < level)
    return FALSE;

  __cpuid (info, level);

  *a = info[0];
  *b = info[1];
  *c = info[2];
  *d = info[3];

  return TRUE;
#else
  guint n;

  n = __get_cpuid_max (0, NULL);
  if (n < level)
    return FALSE;

  __cpuid_count (level, 0, *a, *b, *c, *d);

  return TRUE;
#endif
}


